  "src/lib/docTemplates.js": "",
  "src/lib/exportUtils.js": "",
  "src/lib/license.js": "",
  "src/lib/router.js": "",
  "src/lib/schemas.js": "",
  "src/lib/supabaseClient.js": "",
  "src/lib/theme.js": "",
  "src/lib/uiState.js": "",
